const input = $json;

function parseMaybeJson(value, fallback = {}) {
  if (value && typeof value === "object") return value;
  if (typeof value !== "string") return fallback;

  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

return [{
  ...input,

  lead_id: input.lead_id || input.execution_context?.lead_id || null,
  phone: input.phone || input.execution_context?.phone || null,
  channel: input.channel || input.execution_context?.channel || "whatsapp",

  service_interest: input.service_interest || input.execution_context?.service_interest || null,
  vehicle_type: input.vehicle_type || input.execution_context?.vehicle_type || null,
  district: input.district || input.execution_context?.district || null,

  booking_date: input.booking_date || input.execution_context?.booking_date || null,
  booking_time: input.booking_time || input.execution_context?.booking_time || null,
  slot_id: input.slot_id || input.execution_context?.slot_id || null,

  execution_context: parseMaybeJson(input.execution_context, {}),
  context_packet: parseMaybeJson(input.context_packet, {}),
  decision: parseMaybeJson(input.decision, {}),
  state_update: parseMaybeJson(input.state_update, {}),
  execution_meta: parseMaybeJson(input.execution_meta, {})
}];

const input = $("Normalize Input").first().json;
const appointment = $json || {};

if (!appointment.id) {
  return [{
    ...input,
    message_to_send: "Por ahora no encontré una reserva activa asociada para enviarte las indicaciones previas. Si quieres, reviso tu agendamiento manualmente.",
    db_operations: ["messages", "lead_state"],
    state_update: {
      ...(input.state_update || {}),
      next_goal: "manual_booking_review",
      last_bot_action: "pre_service_instructions_no_active_appointment",
      missing_fields: []
    },
    notes: [
      ...(input.notes || []),
      "no_active_appointment_found_for_pre_service_instructions"
    ]
  }];
}
function formatDateTime(value) {
  if (!value) return "la fecha agendada";

  const d = new Date(value);

  return d.toLocaleString("es-CL", {
    timeZone: "America/Santiago",
    weekday: "long",
    day: "2-digit",
    month: "long",
    hour: "2-digit",
    minute: "2-digit"
  });
}

const appointmentDate = formatDateTime(appointment.start_at);

function serviceLabel(service) {
  const map = {
    lavado_basico: "lavado básico",
    lavado_premium: "lavado premium",
    encerado_full: "encerado full",

    lavado_profundo: "lavado premium",
    lavado_esencial: "lavado básico",
  };

  return map[service] || "el servicio";
}

const service = serviceLabel(input.service_interest);

const vehicle = input.vehicle_type ? ` para tu ${input.vehicle_type}` : "";

const message =
`Perfecto. Te dejo las indicaciones previas para tu ${service}${vehicle} agendado para ${appointmentDate}.

Antes del servicio, idealmente:

1. Deja el vehículo en un lugar accesible y con espacio para trabajar.
2. Retira objetos personales importantes del interior.
3. Si el maletero o los asientos están muy cargados, intenta dejarlos despejados.
4. Ten disponible a alguien al momento de la llegada.
5. Si hay indicaciones especiales del domicilio, portón, conserjería o estacionamiento, nos las puedes enviar por aquí.

Con eso llegamos mejor preparados y evitamos atrasos.`;

return [{
  ...input,

  appointment,

  message_to_send: message,

  db_operations: ["messages", "lead_state"],

  state_update: {
    ...(input.state_update || {}),
    stage: "booked",
    intent_last: "send_pre_service_instructions",
    next_goal: "service_prepared",
    last_bot_action: "send_pre_service_instructions",
    missing_fields: []
  },

  notes: [
    ...(input.notes || []),
    "pre_service_instructions_built"
  ]
}];

